// Complete C solution (uses stdio and manual bitset handling)
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAXK 1005
#define WORDS ((MAXK+63)/64)

int compare_int(const void *a, const void *b) {
    int x = *(int*)a, y = *(int*)b;
    return (x > y) - (x < y);
}

// bitset of size MAXK (up to 1002)
typedef struct { unsigned long long w[WORDS]; } Bitset;

static inline void bitset_set(Bitset *b, int pos) { b->w[pos>>6] |= 1ULL << (pos & 63); }
static inline int bitset_test(const Bitset *b, int pos) { return (b->w[pos>>6] >> (pos & 63)) & 1ULL; }
static inline void bitset_or_shift(Bitset *dest, const Bitset *src) {
    // dest |= src << 1
    unsigned long long carry = 0;
    for (int i = 0; i < WORDS; ++i) {
        unsigned long long cur = src->w[i];
        unsigned long long shifted = (cur << 1) | carry;
        carry = cur >> 63;
        dest->w[i] |= shifted;
    }
}

int feasible(int D, int K, int s, int e, int *P, int steps) {
    Bitset dp[MAXK];
    for (int i = 0; i < K; ++i) memset(dp[i].w, 0, sizeof(dp[i].w));
    bitset_set(&dp[s], 0);
    for (int i = s + 1; i < K; ++i) {
        for (int j = s; j < i; ++j) {
            if (P[i] - P[j] <= D) {
                bitset_or_shift(&dp[i], &dp[j]);
            }
        }
    }
    return bitset_test(&dp[e], steps);
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N, M, C1, C2; scanf("%d %d %d %d", &N, &M, &C1, &C2);
        int total = N + 2;
        int arr[MAXK];
        arr[0] = C1; arr[1] = C2;
        for (int i = 0; i < N; ++i) scanf("%d", &arr[2+i]);
        qsort(arr, total, sizeof(int), compare_int);
        int s = -1, e = -1;
        for (int i = 0; i < total; ++i) {
            if (arr[i] == C1 && s==-1) s = i;
            if (arr[i] == C2 && e==-1) e = i;
        }
        if (s > e) { int tmp = s; s = e; e = tmp; }
        int low = 0, high = arr[total-1] - arr[0];
        while (low < high) {
            int mid = (low + high) / 2;
            if (feasible(mid, total, s, e, arr, M+1)) high = mid; else low = mid + 1;
        }
        printf("%d\n", low);
    }
    return 0;
}
